import sys, json
data = json.load(sys.stdin)
json.dump(data, open('after-cpm-packages.json','w'), indent=2)

# Compare with baseline
baseline = json.load(open('baseline-packages.json'))
def extract(d):
    result = {}
    for p in d['projects']:
        name = p['path'].split('/')[-1]
        for fw in p['frameworks']:
            for pkg in fw.get('topLevelPackages', []):
                result[(name, pkg['id'])] = pkg['resolvedVersion']
    return result

b = extract(baseline)
a = extract(data)
if b == a:
    print('All packages resolve identically to baseline.')
else:
    for k in sorted(set(list(b.keys()) + list(a.keys()))):
        bv = b.get(k, 'MISSING')
        av = a.get(k, 'MISSING')
        if bv != av:
            print(f'CHANGED: {k[0]} {k[1]}: {bv} -> {av}')
"

